const sharp = require\(''sharp''\);
const path = require\(''path''\);

async function processLogo\(\) {
  const src = ''logo-original.png'';

  // 1. Optimized PNG logo \(for the site - 400px wide, good for header/footer\)
  await sharp\(src\)
    .resize\(400, null, { withoutEnlargement: true }\)
    .png\({ quality: 90, compressionLevel: 9 }\)
    .toFile\(''logo.png''\);

  // 2. WebP version for even better performance
  await sharp\(src\)
    .resize\(400, null, { withoutEnlargement: true }\)
    .webp\({ quality: 85 }\)
    .toFile\(''logo.webp''\);

  // 3. OG image version \(larger, for social sharing - 600px\)
  await sharp\(src\)
    .resize\(600, null, { withoutEnlargement: true }\)
    .png\({ quality: 90 }\)
    .toFile\(''logo-og.png''\);

  console.log\(''Logo versions created!''\);

  // Show sizes
  const fs = require\(''fs''\);
  for \(const f of [''logo.png'', ''logo.webp'', ''logo-og.png'']\) {
    const stat = fs.statSync\(f\);
    console.log\(''  '' + f + '': '' + \(stat.size / 1024\).toFixed\(1\) + '' KB''\);
  }
}

processLogo\(\).catch\(console.error\);
